import { Router } from "express";
import { getDb } from "./database";

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type BookmarkInput = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
  folder_id?: unknown;
};

const router = Router();
const db = getDb();

const findBookmark = db
  .prepare("SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE id = ?")
  .pluck(false);

const listBookmarks = db.prepare(
  "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks ORDER BY id ASC",
);

const insertBookmark = db.prepare(`
  INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
  VALUES (@url, @title, @description, @folder_id, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      folder_id = @folder_id,
      updated_at = @updated_at
  WHERE id = @id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ?");
const findFolder = db.prepare("SELECT id FROM folders WHERE id = ?");

function getBookmark(id: number): Bookmark | undefined {
  return findBookmark.get(id) as Bookmark | undefined;
}

function parseId(value: string): number | undefined {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : undefined;
}

function textField(value: unknown): string | undefined {
  return typeof value === "string" ? value.trim() : undefined;
}

function parseDescription(value: unknown): string | null {
  if (value === undefined || value === null) {
    return null;
  }

  return typeof value === "string" ? value : String(value);
}

function parseFolderId(value: unknown): number | null | undefined {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  if (typeof value !== "number" || !Number.isInteger(value) || value <= 0) {
    return undefined;
  }

  return value;
}

function folderExists(folderId: number): boolean {
  return Boolean(findFolder.get(folderId));
}

function validateFolderId(value: unknown): { folder_id: number | null | undefined } | { error: string } {
  const folderId = parseFolderId(value);

  if (folderId === undefined && value !== undefined) {
    return { error: "folder_id must reference an existing folder" };
  }

  if (folderId !== null && folderId !== undefined && !folderExists(folderId)) {
    return { error: "folder_id must reference an existing folder" };
  }

  return { folder_id: folderId };
}

function validateRequiredBookmark(
  input: BookmarkInput,
): { url: string; title: string; description: string | null; folder_id: number | null } | { error: string } {
  const url = textField(input.url);
  const title = textField(input.title);

  if (!url) {
    return { error: "url is required" };
  }

  if (!title) {
    return { error: "title is required" };
  }

  const folder = validateFolderId(input.folder_id);
  if ("error" in folder) {
    return folder;
  }

  return {
    url,
    title,
    description: parseDescription(input.description),
    folder_id: folder.folder_id ?? null,
  };
}

router.post("/", (req, res) => {
  const parsed = validateRequiredBookmark(req.body as BookmarkInput);

  if ("error" in parsed) {
    res.status(400).json({ error: parsed.error });
    return;
  }

  const now = new Date().toISOString();
  const result = insertBookmark.run({
    url: parsed.url,
    title: parsed.title,
    description: parsed.description,
    folder_id: parsed.folder_id,
    created_at: now,
    updated_at: now,
  });

  const bookmark = getBookmark(Number(result.lastInsertRowid));
  res.status(201).json(bookmark);
});

router.get("/", (_req, res) => {
  res.status(200).json(listBookmarks.all() as Bookmark[]);
});

router.get("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const bookmark = id ? getBookmark(id) : undefined;

  if (!bookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(200).json(bookmark);
});

router.put("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const current = id ? getBookmark(id) : undefined;

  if (!id || !current) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const input = req.body as BookmarkInput;
  const url = input.url === undefined ? current.url : textField(input.url);
  const title = input.title === undefined ? current.title : textField(input.title);

  if (!url) {
    res.status(400).json({ error: "url is required" });
    return;
  }

  if (!title) {
    res.status(400).json({ error: "title is required" });
    return;
  }

  const folder = validateFolderId(input.folder_id);
  if ("error" in folder) {
    res.status(400).json({ error: folder.error });
    return;
  }

  updateBookmark.run({
    id,
    url,
    title,
    description: input.description === undefined ? current.description : parseDescription(input.description),
    folder_id: folder.folder_id === undefined ? current.folder_id : folder.folder_id,
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getBookmark(id));
});

router.delete("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const result = id ? deleteBookmark.run(id) : { changes: 0 };

  if (result.changes === 0) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(204).send();
});

export default router;

import { Router } from "express";
import { getDb } from "./database";

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type FolderInput = {
  name?: unknown;
};

const router = Router();
const db = getDb();

const findFolder = db
  .prepare("SELECT id, name, created_at, updated_at FROM folders WHERE id = ?")
  .pluck(false);

const listFolders = db.prepare("SELECT id, name, created_at, updated_at FROM folders ORDER BY id ASC");

const listFolderBookmarks = db.prepare(
  "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE folder_id = ? ORDER BY id ASC",
);

const insertFolder = db.prepare(`
  INSERT INTO folders (name, created_at, updated_at)
  VALUES (@name, @created_at, @updated_at)
`);

const updateFolder = db.prepare(`
  UPDATE folders
  SET name = @name,
      updated_at = @updated_at
  WHERE id = @id
`);

const unfolderBookmarks = db.prepare("UPDATE bookmarks SET folder_id = NULL, updated_at = @updated_at WHERE folder_id = @folder_id");
const deleteFolder = db.prepare("DELETE FROM folders WHERE id = ?");

function getFolder(id: number): Folder | undefined {
  return findFolder.get(id) as Folder | undefined;
}

function parseId(value: string): number | undefined {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : undefined;
}

function parseName(value: unknown): string | undefined {
  return typeof value === "string" ? value.trim() : undefined;
}

function folderWithBookmarks(folder: Folder): Folder & { bookmarks: Bookmark[] } {
  return {
    ...folder,
    bookmarks: listFolderBookmarks.all(folder.id) as Bookmark[],
  };
}

router.post("/", (req, res) => {
  const name = parseName((req.body as FolderInput).name);

  if (!name) {
    res.status(400).json({ error: "name is required" });
    return;
  }

  const now = new Date().toISOString();
  const result = insertFolder.run({
    name,
    created_at: now,
    updated_at: now,
  });

  res.status(201).json(getFolder(Number(result.lastInsertRowid)));
});

router.get("/", (_req, res) => {
  res.status(200).json(listFolders.all() as Folder[]);
});

router.get("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const folder = id ? getFolder(id) : undefined;

  if (!folder) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  res.status(200).json(folderWithBookmarks(folder));
});

router.put("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const folder = id ? getFolder(id) : undefined;

  if (!id || !folder) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  const name = parseName((req.body as FolderInput).name);

  if (!name) {
    res.status(400).json({ error: "name is required" });
    return;
  }

  updateFolder.run({
    id,
    name,
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getFolder(id));
});

router.delete("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const folder = id ? getFolder(id) : undefined;

  if (!id || !folder) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  const now = new Date().toISOString();
  const transaction = db.transaction((folderId: number) => {
    unfolderBookmarks.run({ folder_id: folderId, updated_at: now });
    deleteFolder.run(folderId);
  });

  transaction(id);
  res.status(204).send();
});

export default router;

