118	export function requireAuth(req: Request, res: Response, next: NextFunction): void {
119	  const authorization = req.header("authorization");
120	  const match = authorization?.match(/^Bearer\s+(.+)$/i);
121	
122	  if (!match) {
123	    res.status(401).json({ error: "authentication required" });
124	    return;
125	  }
126	
127	  try {
128	    const payload = jwt.verify(match[1], JWT_SECRET) as JwtPayload;
129	
130	    if (!Number.isInteger(payload.userId) || !findUserById.get(payload.userId)) {
131	      res.status(401).json({ error: "invalid token" });
132	      return;
133	    }
134	
135	    req.userId = payload.userId;
136	    next();
137	  } catch {
